import{_ as t,c as e,o as i,a1 as l}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"빠른 시작: Antigravity Auth 설치 및 설정 | OpenCode","description":"Antigravity Auth 플러그인의 설치 및 설정 방법을 배웁니다. 10분 안에 Google OAuth 인증을 완료하고, 첫 번째 모델 요청을 보내 Claude와 Gemini 모델 접근이 성공했는지 확인합니다.","frontmatter":{"title":"빠른 시작: Antigravity Auth 설치 및 설정 | OpenCode","sidebarTitle":"10분 만에 시작하기","subtitle":"빠른 시작: Antigravity Auth 설치 및 설정","description":"Antigravity Auth 플러그인의 설치 및 설정 방법을 배웁니다. 10분 안에 Google OAuth 인증을 완료하고, 첫 번째 모델 요청을 보내 Claude와 Gemini 모델 접근이 성공했는지 확인합니다.","order":1},"headers":[],"relativePath":"ko/NoeFabris/opencode-antigravity-auth/start/index.md","filePath":"ko/NoeFabris/opencode-antigravity-auth/start/index.md"}'),r={name:"ko/NoeFabris/opencode-antigravity-auth/start/index.md"};function o(n,a,h,u,s,d){return i(),e("div",null,[...a[0]||(a[0]=[l('<h1 id="빠른-시작" tabindex="-1">빠른 시작 <a class="header-anchor" href="#빠른-시작" aria-label="Permalink to &quot;빠른 시작&quot;">​</a></h1><p>본 섹션에서는 Antigravity Auth 플러그인을 처음부터 사용하는 방법을 안내합니다. 플러그인의 핵심 가치를 이해하고, 설치 및 OAuth 인증을 완료한 후, 첫 번째 모델 요청을 보내 설정이 성공했는지 확인합니다.</p><h2 id="학습-경로" tabindex="-1">학습 경로 <a class="header-anchor" href="#학습-경로" aria-label="Permalink to &quot;학습 경로&quot;">​</a></h2><p>다음 순서대로 학습하세요. 각 단계는 이전 단계를 기반으로 합니다:</p><h3 id="_1-플러그인-소개" tabindex="-1">1. <a href="./what-is-antigravity-auth/">플러그인 소개</a> <a class="header-anchor" href="#_1-플러그인-소개" aria-label="Permalink to &quot;1. [플러그인 소개](./what-is-antigravity-auth/)&quot;">​</a></h3><p>Antigravity Auth 플러그인의 핵심 가치, 적용 시나리오 및 위험 안내를 알아봅니다.</p><ul><li>플러그인이 사용 시나리오에 적합한지 판단</li><li>지원되는 AI 모델 확인 (Claude Opus 4.5, Sonnet 4.5, Gemini 3 Pro/Flash)</li><li>사용 위험 및 주의사항 명확히 이해</li></ul><h3 id="_2-빠른-설치" tabindex="-1">2. <a href="./quick-install/">빠른 설치</a> <a class="header-anchor" href="#_2-빠른-설치" aria-label="Permalink to &quot;2. [빠른 설치](./quick-install/)&quot;">​</a></h3><p>5분 만에 플러그인 설치와 첫 인증을 완료합니다.</p><ul><li>두 가지 설치 방법 (AI 지원 / 수동 설정)</li><li>모델 정의 설정</li><li>Google OAuth 인증 실행</li></ul><h3 id="_3-oauth-2-0-pkce-인증" tabindex="-1">3. <a href="./first-auth-login/">OAuth 2.0 PKCE 인증</a> <a class="header-anchor" href="#_3-oauth-2-0-pkce-인증" aria-label="Permalink to &quot;3. [OAuth 2.0 PKCE 인증](./first-auth-login/)&quot;">​</a></h3><p>OAuth 2.0 PKCE 인증 흐름을 이해하고 첫 로그인을 완료합니다.</p><ul><li>PKCE 인증의 보안 메커니즘 이해</li><li>첫 로그인으로 API 접근 권한 획득</li><li>토큰 갱신의 자동화 처리 이해</li></ul><h3 id="_4-첫-번째-요청" tabindex="-1">4. <a href="./first-request/">첫 번째 요청</a> <a class="header-anchor" href="#_4-첫-번째-요청" aria-label="Permalink to &quot;4. [첫 번째 요청](./first-request/)&quot;">​</a></h3><p>첫 번째 모델 요청을 보내 설치 성공을 확인합니다.</p><ul><li>첫 번째 Antigravity 모델 요청 전송</li><li><code>--model</code> 및 <code>--variant</code> 매개변수 이해</li><li>일반적인 모델 요청 오류 해결</li></ul><h2 id="사전-요구사항" tabindex="-1">사전 요구사항 <a class="header-anchor" href="#사전-요구사항" aria-label="Permalink to &quot;사전 요구사항&quot;">​</a></h2><p>본 섹션을 시작하기 전에 확인하세요:</p><ul><li>✅ OpenCode CLI 설치 완료 (<code>opencode</code> 명령어 사용 가능)</li><li>✅ Google 계정 보유 (OAuth 인증용)</li></ul><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><p>빠른 시작을 완료한 후:</p><ul><li><strong><a href="./../platforms/available-models/">사용 가능한 모델 알아보기</a></strong> — 지원되는 모든 모델과 변형 설정 탐색</li><li><strong><a href="./../advanced/multi-account-setup/">다중 계정 설정</a></strong> — 여러 Google 계정으로 할당량 풀링 설정</li><li><strong><a href="./../faq/common-auth-issues/">일반적인 인증 문제</a></strong> — 문제 발생 시 문제 해결 가이드 참조</li></ul>',22)])])}const f=t(r,[["render",o]]);export{p as __pageData,f as default};
